const ASSETS = {
  '/assets/index-NqSbHPCr.css': { data: '', type: 'text/css' },
  '/assets/index-YRpeNmTH.js': { data: '', type: 'application/javascript' },
  '/manifest.json': { data: 'eyJuYW1lIjoiU2hlbGYiLCJzaG9ydF9uYW1lIjoiU2hlbGYiLCJ0aGVtZV9jb2xvciI6IiMwYTBhMGMiLCJiYWNrZ3JvdW5kX2NvbG9yIjoiIzBhMGEwYyIsImRpc3BsYXkiOiJzdGFuZGFsb25lIn0=', type: 'application/json' },
};
const INDEX_HTML = '';

function b64decode(str) {
  const bin = atob(str);
  const bytes = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
  return bytes;
}

export default {
  async fetch(request) {
    const url = new URL(request.url);
    const path = url.pathname;

    const asset = ASSETS[path];
    if (asset) {
      const headers = { 'Content-Type': asset.type, 'Cache-Control': path.includes('-') ? 'public, max-age=31536000, immutable' : 'public, max-age=3600' };
      return new Response(b64decode(asset.data), { headers });
    }

    return new Response(b64decode(INDEX_HTML), {
      headers: { 'Content-Type': 'text/html; charset=utf-8', 'Cache-Control': 'no-cache' },
    });
  },
};
